/// Secure UUID generator using Dart's Random.secure()
class UuidGenerator {
  static final Random _secureRandom = Random.secure();

  /// Generates a UUID v4 compliant string
  static String generateV4() {
    final bytes = List<int>.generate(16, (_) => _secureRandom.nextInt(256));

    // Set version to 4 (0100 in binary)
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary)
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _bytesToUuid(bytes);
  }

  /// Generates a time-based UUID with random components for offline uniqueness
  static String generateTimeBased() {
    final now = DateTime.now().toUtc();
    final timestamp = now.microsecondsSinceEpoch;

    // 8 bytes from timestamp
    final timeBytes = <int>[
      (timestamp >> 56) & 0xFF,
      (timestamp >> 48) & 0xFF,
      (timestamp >> 40) & 0xFF,
      (timestamp >> 32) & 0xFF,
      (timestamp >> 24) & 0xFF,
      (timestamp >> 16) & 0xFF,
      (timestamp >> 8) & 0xFF,
      timestamp & 0xFF,
    ];

    // 8 random bytes for uniqueness
    final randomBytes =
        List<int>.generate(8, (_) => _secureRandom.nextInt(256));

    final bytes = [...timeBytes, ...randomBytes];

    // Set version to 4
    bytes[6] = (bytes[6] & 0x0F) | 0x40;
    // Set variant to RFC 4122
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _bytesToUuid(bytes);
  }

  /// Generates a short unique ID (12 hex characters) for compact storage
  static String generateShortId() {
    final timestamp = DateTime.now().toUtc().microsecondsSinceEpoch & 0xFFFFFFFF;
    final randomPart = _secureRandom.nextInt(0xFFFF);

    final bytes = <int>[
      (timestamp >> 24) & 0xFF,
      (timestamp >> 16) & 0xFF,
      (timestamp >> 8) & 0xFF,
      timestamp & 0xFF,
      (randomPart >> 8) & 0xFF,
      randomPart & 0xFF,
    ];

    return bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
  }

  /// Converts a list of 16 bytes to a UUID string format
  static String _bytesToUuid(List<int> bytes) {
    assert(bytes.length == 16);
    final hex =
        bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();

    return '${hex.substring(0, 8)}-'
        '${hex.substring(8, 12)}-'
        '${hex.substring(12, 16)}-'
        '${hex.substring(16, 20)}-'
        '${hex.substring(20, 32)}';
  }

  /// Validates if a string is a valid UUID format
  static bool isValidUuid(String uuid) {
    final regex = RegExp(
      r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
      caseSensitive: false,
    );
    return regex.hasMatch(uuid);
  }
}

/// Represents an offline data entry with a unique ID
class OfflineDataEntry {
  final String id;
  final String title;
  final String content;
  final DateTime createdAt;
  final bool isSynced;

  OfflineDataEntry({
    required this.id,
    required this.title,
    required this.content,
    required this.createdAt,
    this.isSynced = false,
  });

  OfflineDataEntry copyWith({
    String? id,
    String? title,
    String? content,
    DateTime? createdAt,
    bool? isSynced,
  }) {
    return OfflineDataEntry(
      id: id ?? this.id,
      title: title ?? this.title,
      content: content ?? this.content,
      createdAt: createdAt ?? this.createdAt,
      isSynced: isSynced ?? this.isSynced,
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'title': title,
      'content': content,
      'createdAt': createdAt.toIso8601String(),
      'isSynced': isSynced,
    };
  }

  factory OfflineDataEntry.fromJson(Map<String, dynamic> json) {
    return OfflineDataEntry(
      id: json['id'] as String,
      title: json['title'] as String,
      content: json['content'] as String,
      createdAt: DateTime.parse(json['createdAt'] as String),
      isSynced: json['isSynced'] as bool? ?? false,
    );
  }
}

/// In-memory store for offline entries (replace with persistent storage in production)
class OfflineDataStore {
  final List<OfflineDataEntry> _entries = [];
  final Set<String> _usedIds = {};

  List<OfflineDataEntry> get entries => List.unmodifiable(_entries);

  int get unsyncedCount => _entries.where((e) => !e.isSynced).length;

  OfflineDataEntry createEntry({
    required String title,
    required String content,
  }) {
    // Sanitize inputs
    final sanitizedTitle = _sanitize(title);
    final sanitizedContent = _sanitize(content);

    if (sanitizedTitle.isEmpty) {
      throw ArgumentError('Title cannot be empty');
    }

    // Generate a unique ID, ensuring no collisions
    String id;
    int attempts = 0;
    const maxAttempts = 100;

    do {
      id = UuidGenerator.generateV4();
      attempts++;
      if (attempts > maxAttempts) {
        throw StateError('Failed to generate unique ID after $maxAttempts attempts');
      }
    } while (_usedIds.contains(id));

    _usedIds.add(id);

    final entry = OfflineDataEntry(
      id: id,
      title: sanitizedTitle,
      content: sanitizedContent,
      createdAt: DateTime.now().toUtc(),
    );

    _entries.add(entry);
    return entry;
  }

  void markAsSynced(String id) {
    final index = _entries.indexWhere((e) => e.id == id);
    if (index != -1) {
      _entries[index] = _entries[index].copyWith(isSynced: true);
    }
  }

  void deleteEntry(String id) {
    _entries.removeWhere((e) => e.id == id);
    _usedIds.remove(id);
  }

  List<OfflineDataEntry> getUnsyncedEntries() {
    return _entries.where((e) => !e.isSynced).toList();
  }

  /// Simulate syncing all unsynced entries
  Future<int> simulateSync() async {
    await Future.delayed(const Duration(seconds: 1));
    final unsynced = getUnsyncedEntries();
    for (final entry in unsynced) {
      markAsSynced(entry.id);
    }
    return unsynced.length;
  }

  String _sanitize(String input) {
    return input.trim().replaceAll(RegExp(r'[\x00-\x08\x0B\x0C\x0E-\x1F]'), '');
  }
}

